    node.warn('No location yet');
    return null;
}

node.status({fill:'red', shape:'dot', text:'🚨 THREAT ACTIVE'});
return msg;

const CHAT_ID = '-5148615810';

if (!msg.lat || !msg.lng) return null;

msg.payload = {
    chatId: CHAT_ID,
    type: 'location',
    content: {
        latitude:  msg.lat,
        longitude: msg.lng
    }
};
return msg;

const CHAT_ID = '-5295226131';

if (!msg.photoUrl) {
    node.warn('No photo URL yet');
    return null;
}

// Telegram can send photo directly from URL
msg.payload = {
    chatId: CHAT_ID,
    type: 'photo',
    content: msg.photoUrl,
    options: {
        caption: `📸 Latest capture\n🕐 ${msg.timestamp}`
    }
};
return msg;

